CREATE TABLE IF NOT EXISTS players (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), handle text NOT NULL, display_name text NOT NULL, avatar_url text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS players_handle_ux ON players (lower(handle));
CREATE TABLE IF NOT EXISTS show_state (id integer PRIMARY KEY DEFAULT 1, state text NOT NULL DEFAULT 'idle', scene_profile text NOT NULL DEFAULT 'default', theme text NOT NULL DEFAULT 'jackpot_ps5', updated_by text, updated_at timestamptz NOT NULL DEFAULT now());
INSERT INTO show_state (id, state, scene_profile, theme) VALUES (1, 'idle', 'default', 'jackpot_ps5') ON CONFLICT (id) DO NOTHING;
CREATE TABLE IF NOT EXISTS assets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), theme text NOT NULL, layer text NOT NULL CHECK (layer IN ('0','1','2','3','3.5','4')), variant text NOT NULL DEFAULT 'default', version integer NOT NULL DEFAULT 1, url text NOT NULL, cdn_url text, mime_type text NOT NULL, width integer, height integer, fps integer, alpha_present boolean NOT NULL DEFAULT false, hash_sha256 text, audio_codec text, duration_ms integer, active boolean NOT NULL DEFAULT false, deprecated boolean NOT NULL DEFAULT false, readonly boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), created_by text, last_used_at timestamptz, meta jsonb DEFAULT '{}'::jsonb);
